1	// Smoke test for the deployed auth-signup-lister edge function.
2	//
3	// Usage: bun run scripts/test/auth-signup-lister.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY in .env (bun auto-loads).
5	//
6	// Asserts:
7	//   1. Fresh { username, email, org_name } → 200 with { token, user_id, role:'lister' }
8	//   2. Same body again → 409 USERNAME_TAKEN (username hits first)
9	//   3. Missing org_name → 400 INVALID_REQUEST
10	
11	const supabaseUrl = process.env.SUPABASE_URL;
12	const anonKey = process.env.SUPABASE_ANON_KEY;
13	if (!supabaseUrl || !anonKey) {
14	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
15	  process.exit(1);
16	}
17	
18	const endpoint = `${supabaseUrl}/functions/v1/auth-signup-lister`;
19	const baseHeaders = {
20	  "Content-Type": "application/json",
21	  Authorization: `Bearer ${anonKey}`,
22	  apikey: anonKey,
23	};
24	
25	const unique = Date.now();
26	const payload = {
27	  username: `us014_test_${unique}`,
28	  email: `us014_test_${unique}@marketify.test`,
29	  org_name: "US-014 Test Org",
30	  website_url: "https://us014.test",
31	};
32	
33	async function post(body: unknown) {
34	  const res = await fetch(endpoint, {
35	    method: "POST",
36	    headers: baseHeaders,
37	    body: JSON.stringify(body),
38	  });
39	  const data = await res.json().catch(() => null);
40	  return { status: res.status, data };
41	}
42	
43	const first = await post(payload);
44	console.log("first:", first.status, first.data);
45	if (first.status !== 200) process.exit(1);
46	if (
47	  typeof first.data?.token !== "string" ||
48	  typeof first.data?.user_id !== "string" ||
49	  first.data?.role !== "lister"
50	) {
51	  console.error("unexpected 200 body shape");
52	  process.exit(1);
53	}
54	
55	const second = await post(payload);
56	console.log("second:", second.status, second.data);
57	if (second.status !== 409 || second.data?.error !== "USERNAME_TAKEN") {
58	  console.error("expected 409 USERNAME_TAKEN");
59	  process.exit(1);
60	}
61	
62	const third = await post({ username: `us014_test_other_${unique}`, email: `us014_test_other_${unique}@marketify.test` });
63	console.log("third:", third.status, third.data);
64	if (third.status !== 400 || third.data?.error !== "INVALID_REQUEST") {
65	  console.error("expected 400 INVALID_REQUEST");
66	  process.exit(1);
67	}
68	
69	console.log("ok — created user_id:", first.data.user_id);
